scwin.excelDown = async function(gubun) {
    var fileName = "Container in Korea List Summary";

    if (ds_retrieve.getRowCount() != 0) {
        let confirm = await $c.win.confirm("EXCEL로 다운로드 받으시겠습니까?");
        if (confirm) {
            await $c.data.downloadGridViewExcel(gr_workImplement, { fileName: fileName + ".xlsx", sheetName: fileName});
        }
    } else {
        $c.gus.cfAlertMsg(MSG_CM_WRN_002);
    }
};
